{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string? Description { get; set; }
    public bool IsActive { get; set; }
}

// PartialClass reuses class constructors, but mapping members stay user-authored.
[GenerateDtos(Types = DtoTypes.Create | DtoTypes.Update | DtoTypes.Response, OutputType = OutputType.PartialClass)]
public class TestPartialClassEntity
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string? Description { get; set; }
    public bool IsActive { get; set; }
}

public partial class UpdateTestPartialClassEntityRequest
{
    public string DisplayLabel => $"{Id}: {Name}";
}

[GenerateDtos(Types = DtoTypes.Create | DtoTypes.Update | DtoTypes.Response, OutputType = OutputType.Interface)]
[GenerateDtos(Types = DtoTypes.Create | DtoTypes.Update | DtoTypes.Response, OutputType = OutputType.PartialClass)]
public class TestPartialAndInterfaceEntity
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public bool IsActive { get; set; }
}

// PartialClass intentionally NOT sealed: a hand-written derived type should compile.

public class DerivedFromGeneratedPartial : UpdateTestPartialClassEntityRequest
{
    public string DerivedOnly { get; set; } = string.Empty;
}

// OutputType is [Flags]: one attribute emits an Interface + PartialClass pair.
[GenerateDtos(Types = DtoTypes.Create | DtoTypes.Update,
    OutputType = OutputType.Interface | OutputType.PartialClass)]
public class TestOutputTypeFlagsEntity
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public bool IsActive { get; set; }
}

// Interface pairing generalizes past PartialClass: a flags-combined Record output
// implements the sibling interface generated by the same attribute.
[GenerateDtos(Types = DtoTypes.Update,
    OutputType = OutputType.Interface | OutputType.Record)]
public class TestRecordInterfacePairEntity
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
}

// Structs can implement interfaces too — record struct output pairs the same way.
[GenerateDtos(Types = DtoTypes.Update,
    OutputType = OutputType.Interface | OutputType.RecordStruct)]
public class TestStructInterfacePairEntity
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
}

// Partial is a modifier composable with any kind: Record | Partial emits a partial
// record (constructors kept, mapping members omitted) that a hand-written half extends.
[GenerateDtos(Types = DtoTypes.Update,
    OutputType = OutputType.Record | OutputType.Partial)]
public class TestPartialRecordEntity
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
}

// Compile-time proof the generated record is partial: this half only compiles if the
// generated declaration is 'partial record'.
public partial record UpdateTestPartialRecordEntityRequest
{
    public string DisplayLabel => $"{Id}: {Name}";
}

// The modifier composes with Interface too: one attribute yields a partial record struct
// implementing a partial interface — both halves user-extensible.
[GenerateDtos(Types = DtoTypes.Update,
    OutputType = OutputType.Interface | OutputType.RecordStruct | OutputType.Partial,
    Prefix = "Mod")]
public class TestPartialStructInterfaceEntity
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
}

// Compile-time proof the generated interface is partial.
public partial interface IUpdateModTestPartialStructInterfaceEntityRequest
{
}

// ExcludeNavigationProperties is driven by the EF model manifest and has no heuristic
// fallback, so it cannot be exercised through statically-compiled entities here (there is no
// manifest AdditionalFile for this test project — such an entity would be a FAC105 error).
// Its behavior is covered by the driver-based GenerateDtosManifestNavigationTests /
// GenerateDtosManifestDiagnosticsTests, which supply an in-memory manifest.
